        image_demo.setMoveAnimationEndedAction(move_in_image_demoEndedCallback);
        //move_in_static_demo
        //When close_btn clicked move static_demo
        //Move static_demo to x:370, y:210 with SineIn easing in 800 ms (48 Ticks)
        static_demo.clearMoveAnimationEndedAction();
